package com.fanmes.common.security;
import jakarta.servlet.http.HttpServletRequest; import org.aspectj.lang.*; import org.aspectj.lang.annotation.*; import org.aspectj.lang.reflect.MethodSignature; import org.springframework.core.annotation.AnnotatedElementUtils; import org.springframework.stereotype.Component;
@Aspect @Component public class PermissionCheckAspect { private final HttpServletRequest request; public PermissionCheckAspect(HttpServletRequest request){this.request=request;} @Around("@annotation(com.fanmes.common.security.RequirePermission) || @within(com.fanmes.common.security.RequirePermission)") public Object check(ProceedingJoinPoint p)throws Throwable{MethodSignature s=(MethodSignature)p.getSignature();RequirePermission required=AnnotatedElementUtils.findMergedAnnotation(s.getMethod(),RequirePermission.class);if(required==null)required=AnnotatedElementUtils.findMergedAnnotation(p.getTarget().getClass(),RequirePermission.class);if(required==null)return p.proceed();Object value=request.getAttribute(JwtAuthenticationFilter.AUTHENTICATED_USER_ATTRIBUTE);if(!(value instanceof AuthenticatedUser u)||!u.permissions().contains(required.value()))throw new PermissionDeniedException("缺少权限: "+required.value());return p.proceed();} }
